Sure! Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:
```
#include <iostream>
#include <fstream>
#include <string>

using namespace std;

int main() {
    // File name
    string filename = "example.txt";

    // Word to count
    string wordToCount = "hello";

    // Count variable
    int count = 0;

    // Open the file
    ifstream file(filename);

    // Check if the file opened successfully
    if (file.is_open()) {
        // Read the file line by line
        string line;
        while (getline(file, line)) {
            // Check if the current line contains the word
            if (line.find(wordToCount) != string::npos) {
                // Increment the count
                count++;
            }
        }
        // Close the file
        file.close();
    } else {
        cout << "Error: Could not open file " << filename << endl;
    }

    // Print the count
    cout << "The word " << wordToCount << " appears " << count << " times in the file." << endl;

    return 0;
}
```
Here's how the program works:

1. We first define the file name, the word to count, and an integer variable to store the count.
2. We open the file using the `ifstream` class, and check if the file opened successfully.
3. We read the file line by line using the `getline` function, and for each line, we check if it contains the word we're looking for using the `find` function. If it does, we increment the count variable.
4. After reading all the lines, we close the file and print the count to the console.

